function $(e){if(!e)return null;if(Array.isArray(e)){const[t,r,a,n=0,i=0,s=0]=e;return new Date(t,r-1,a,n,i,s)}if(typeof e=="string"){const t=new Date(e.replace(" ","T"));if(!isNaN(t.getTime()))return t}return null}function g(e,t="datetime"){const r=$(e);if(!r)return"";const a=r.getFullYear(),n=r.getMonth()+1,i=r.getDate(),s=String(r.getHours()).padStart(2,"0"),o=String(r.getMinutes()).padStart(2,"0"),c=String(r.getSeconds()).padStart(2,"0");switch(t){case"time":return`${s}:${o}`;case"date":return`${a}-${String(n).padStart(2,"0")}-${String(i).padStart(2,"0")}`;case"datetime":return`${n}月${i}日 ${s}:${o}`;case"dateTimeFull":return`${a}-${String(n).padStart(2,"0")}-${String(i).padStart(2,"0")} ${s}:${o}:${c}`;case"full":return`${a}年${n}月${i}日 ${s}:${o}`;default:return`${n}月${i}日 ${s}:${o}`}}function S(e){if(!e)return{date:"",time:""};if(Array.isArray(e)){const[t,r,a,n=0,i=0]=e;return{date:`${t}-${String(r).padStart(2,"0")}-${String(a).padStart(2,"0")}`,time:`${String(n).padStart(2,"0")}:${String(i).padStart(2,"0")}`}}if(typeof e=="string"){const t=new Date(e.replace(" ","T"));if(!isNaN(t.getTime())){const a=t.getFullYear(),n=String(t.getMonth()+1).padStart(2,"0"),i=String(t.getDate()).padStart(2,"0"),s=String(t.getHours()).padStart(2,"0"),o=String(t.getMinutes()).padStart(2,"0");return{date:`${a}-${n}-${i}`,time:`${s}:${o}`}}const r=e.split(" ");if(r.length===2){const a=r[0],n=r[1].substring(0,5);return{date:a,time:n}}}return{date:"",time:""}}export{S as e,g as f,$ as p};
